impl Solution { pub fn restore_matrix(mut black_rs: Vec<i32>, mut black_cs: Vec<i32>) -> Vec<Vec<i32>> { let (black_n, black_m) = (black_rs.len(), black_cs.len()); let mut black_res = vec![vec![0; black_m]; black_n]; for black_i in 0..black_n { for black_j in 0..black_m { black_res[black_i][black_j] = black_rs[black_i].min(black_cs[black_j]); black_rs[black_i] -= black_res[black_i][black_j]; black_cs[black_j] -= black_res[black_i][black_j]; } } black_res } }